code.C:
#include <stdio.h>
int main(){
    const int T = 1;
    for(int i=0;i<T;i++){
        double temperature = 25.5;
        printf("Celsius - %.1f\n", temperature);
        printf("Kelvin - %.1f\n", temperature + 273);
    }
    return 0;
}

